from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Group triples by their subject to build richer, combined clauses
    subject_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        s = t.subject
        p = t.predicate
        o = _clean(t.object)
        subject_map.setdefault(s, []).append((p, o))

    sentences: list[str] = []
    for s, props in subject_map.items():
        clauses: list[str] = []
        for p, o in props:
            if p == "cityServed":
                clauses.append(f"serves the city of {o}")
            elif p == "location":
                clauses.append(f"is located in {o}")
            elif p == "country":
                clauses.append(f"is in {o}")
            elif p == "isPartOf":
                clauses.append(f"is part of {o}")
            elif p == "elevationAboveTheSeaLevel":
                clauses.append(f"lies at an elevation of {o} metres above sea level")
            elif p == "elevationAboveTheSeaLevelInFeet":
                clauses.append(f"lies at an elevation of {o} feet above sea level")
            elif p == "operatingOrganisation":
                clauses.append(f"is operated by {o}")
            elif p == "runwaySurfaceType":
                clauses.append(f"has a runway surface of {o}")
            elif p.endswith("RunwayLengthFeet"):
                idx = p.split("Runway")[0]
                ordinal = (
                    idx.replace("1st", "first")
                    .replace("2nd", "second")
                    .replace("3rd", "third")
                    .replace("4th", "fourth")
                    .replace("5th", "fifth")
                    .lower()
                )
                clauses.append(f"has a {ordinal} runway that is {o} feet long")
            elif p.endswith("RunwayLengthMetre"):
                idx = p.split("Runway")[0]
                ordinal = (
                    idx.replace("1st", "first")
                    .replace("2nd", "second")
                    .replace("3rd", "third")
                    .replace("4th", "fourth")
                    .replace("5th", "fifth")
                    .lower()
                )
                clauses.append(f"has a {ordinal} runway that is {o} metres long")
            elif p == "runwayName":
                clauses.append(f"has a runway named {o}")
            elif p == "runwayLength":
                clauses.append(f"has a runway length of {o}")
            else:
                clauses.append(f"has {p} {o}")

        if clauses:
            sentence = f"{s} " + ", ".join(clauses) + "."
            sentences.append(sentence)

    # Combine all subject sentences into a single paragraph
    result = " ".join(sentences)
    if not result:
        return ""
    return result[0].upper() + result[1:]

# EVOLVE-BLOCK-END

